  "cascading_mixture_itext_noitext.xml": {
    "modifiedTime": 1748279922459,
    "html_form": "<form autocomplete=\"off\" novalidate=\"novalidate\" class=\"or clearfix\" dir=\"ltr\" data-form-id=\"CascadingTripleSelect\">\n<!--This form was created by transforming an ODK/OpenRosa-flavored (X)Form using an XSL stylesheet created by Enketo LLC.--><section class=\"form-logo\"></section><h3 dir=\"auto\" id=\"form-title\">Cascading Triple Select Form</h3><select id=\"form-languages\" data-default-lang=\"\"><option value=\"en\" data-dir=\"ltr\">english</option> <option value=\"it\" data-dir=\"ltr\">italian</option> </select>\n  \n  \n    <fieldset class=\"question simple-select \"><fieldset><legend>\n                    </legend><div class=\"option-wrapper\"><label class=\"itemset-template\" data-items-path=\"instance('choices')/states/state\"><input type=\"radio\" name=\"/form/state\" data-name=\"/form/state\" data-type-xml=\"select1\" value=\"\"></label><span class=\"itemset-labels\" data-value-ref=\"value\" data-label-type=\"itext\" data-label-ref=\"value\"><span lang=\"en\" class=\"option-label active\" data-itext-id=\"washington\">Washington State</span><span lang=\"it\" class=\"option-label \" data-itext-id=\"washington\">State of Washington</span><span lang=\"en\" class=\"option-label active\" data-itext-id=\"illinois\">Illinois State</span><span lang=\"it\" class=\"option-label \" data-itext-id=\"illinois\">State of Illinois</span> </span></div></fieldset></fieldset>\n    <fieldset class=\"question simple-select \"><fieldset><legend>\n                    </legend><div class=\"option-wrapper\"><label class=\"itemset-template\" data-items-path=\"instance('choices')/states/state[value=/form/state]/counties/county\"><input type=\"radio\" name=\"/form/county\" data-name=\"/form/county\" data-type-xml=\"select1\" value=\"\"></label><span class=\"itemset-labels\" data-value-ref=\"value\" data-label-type=\"itext\" data-label-ref=\"value\"><span lang=\"en\" class=\"option-label active\" data-itext-id=\"king\">King County</span><span lang=\"it\" class=\"option-label \" data-itext-id=\"king\">County King</span><span lang=\"en\" class=\"option-label active\" data-itext-id=\"pierce\">Pierce County</span><span lang=\"it\" class=\"option-label \" data-itext-id=\"pierce\">County Pierce</span><span lang=\"en\" class=\"option-label active\" data-itext-id=\"douglas\">Douglas County</span><span lang=\"it\" class=\"option-label \" data-itext-id=\"douglas\">County Douglas</span><span lang=\"en\" class=\"option-label active\" data-itext-id=\"cook\">Cook County</span><span lang=\"it\" class=\"option-label \" data-itext-id=\"cook\">County Cook</span><span lang=\"en\" class=\"option-label active\" data-itext-id=\"douglas-il\">Douglas County</span><span lang=\"it\" class=\"option-label \" data-itext-id=\"douglas-il\">County Douglas</span> </span></div></fieldset></fieldset>\n    <fieldset class=\"question simple-select \"><fieldset><legend>\n                    </legend><div class=\"option-wrapper\"><label class=\"itemset-template\" data-items-path=\"instance('choices')/states/state[value=/form/state]/counties/county[value=/form/county]/cities/city\"><input type=\"radio\" name=\"/form/city\" data-name=\"/form/city\" data-type-xml=\"select1\" value=\"\"></label><span class=\"itemset-labels\" data-value-ref=\"value\" data-label-ref=\"name\"> </span></div></fieldset></fieldset>\n  \n</form>",
    "xml_model": "<model><instance>\n        <form xmlns:jr=\"http://openrosa.org/javarosa\" id=\"CascadingTripleSelect\" version=\"2012072301\">\n          <state/>\n          <county/>\n          <city/>\n        <meta><instanceID/></meta></form>\n      </instance><instance id=\"choices\">\n        <states xmlns:jr=\"http://openrosa.org/javarosa\">\n          <state>\n            <value>washington</value>\n            <counties>\n              <county>\n                <value>king</value>\n                <cities>\n                  <city>\n                    <name>Seattle</name>\n                    <value>sea</value>\n                  </city>\n                  <city>\n                    <name>Redmond</name>\n                    <value>red</value>\n                  </city>\n                </cities>\n              </county>\n              <county>\n                <value>pierce</value>\n                <cities>\n                  <city>\n                    <name>Tacoma</name>\n                    <value>tac</value>\n                  </city>\n                  <city>\n                    <name>Puyallup</name>\n                    <value>puy</value>\n                  </city>\n                </cities>\n              </county>\n              <county>\n                <value>douglas</value>\n                <cities>\n                  <city>\n                    <name>Bridgeport</name>\n                    <value>bri</value>\n                  </city>\n                  <city>\n                    <name>Coulee Dam</name>\n                    <value>cod</value>\n                  </city>\n                  <city>\n                    <name>East Wenatchee</name>\n                    <value>ewe</value>\n                  </city>\n                  <city>\n                    <name>Rock Island</name>\n                    <value>roi</value>\n                  </city>\n                </cities>\n              </county>\n            </counties>\n          </state>\n          <state>\n            <value>illinois</value>\n            <counties>\n              <county>\n                <value>cook</value>\n                <cities>\n                  <city>\n                    <name>Chicago</name>\n                    <value>chi</value>\n                  </city>\n                  <city>\n                    <name>Oak Lawn</name>\n                    <value>oal</value>\n                  </city>\n                  <city>\n                    <name>Oak Forest</name>\n                    <value>oaf</value>\n                  </city>\n                </cities>\n              </county>\n              <county>\n                <value>douglas-il</value>\n                <cities>\n                  <city>\n                    <name>Arcola</name>\n                    <value>arc</value>\n                  </city>\n                  <city>\n                    <name>Tuscola</name>\n                    <value>tus</value>\n                  </city>\n                  <city>\n                    <name>Villa Grove</name>\n                    <value>vig</value>\n                  </city>\n                </cities>\n              </county>\n            </counties>\n          </state>\n        </states>\n      </instance></model>"
  },
