    "html_form": "<form autocomplete=\"off\" novalidate=\"novalidate\" class=\"or clearfix\" dir=\"ltr\" data-form-id=\"6\">\n<!--This form was created by transforming an ODK/OpenRosa-flavored (X)Form using an XSL stylesheet created by Enketo LLC.--><section class=\"form-logo\"></section><h3 dir=\"auto\" id=\"form-title\">Vital Signs</h3>\n    \n    \n        <fieldset class=\"question simple-select \"><fieldset><legend><span lang=\"\" class=\"question-label active\">Was blood pressure measured?</span>\n                    </legend><div class=\"option-wrapper\"><label class=\"\"><input type=\"radio\" name=\"/data/yn\" data-name=\"/data/yn\" value=\"1\" data-type-xml=\"string\"><span lang=\"\" class=\"option-label active\">Yes</span></label></div></fieldset></fieldset>\n        <section class=\"or-group-data or-branch pre-init \" name=\"/data/rg\" data-relevant=\" /data/yn  = 1\"><section class=\"or-repeat \" name=\"/data/rg\">\n            </section><div class=\"or-repeat-info\" data-name=\"/data/rg\"></div>\n            </section><!--end of group -->\n    \n<fieldset id=\"or-calculated-items\" style=\"display:none;\"><label class=\"or-branch pre-init calculation non-select \"><input type=\"hidden\" name=\"/data/rg/is-first-row\" data-relevant=\"position(..) = /data/yn\" data-calculate=\"position(..)\" data-type-xml=\"int\"></label></fieldset></form>",
