    "html_form": "<form autocomplete=\"off\" novalidate=\"novalidate\" class=\"or clearfix pages theme-grid\" dir=\"ltr\" data-form-id=\"PSS\">\n<!--This form was created by transforming an ODK/OpenRosa-flavored (X)Form using an XSL stylesheet created by Enketo LLC.--><section class=\"form-logo\"></section><h3 dir=\"auto\" id=\"form-title\">Post Surgery Summary Form</h3>\n  \n  \n    <section class=\"or-group or-appearance-w4 or-appearance-field-list\" name=\"/data/PROCEDURE\"><h4><span lang=\"\" class=\"question-label active\">Procedure(s)</span></h4><label class=\"question non-select or-appearance-w4\"><span lang=\"\" class=\"question-label active\"><h5>Surgical Procedures</h5></span><input type=\"text\" name=\"/data/PROCEDURE/PROC_NOTE\" data-type-xml=\"string\" readonly></label><section class=\"or-group-data \" name=\"/data/PROCEDURE/PROC_GRID\"><section class=\"or-repeat or-appearance-w4\" name=\"/data/PROCEDURE/PROC_GRID\"><label class=\"question or-appearance-w1 or-appearance-minimal\"><span lang=\"\" class=\"question-label active\"><h6>Procedure:</h6></span><span class=\"required\">*</span><select name=\"/data/PROCEDURE/PROC_GRID/PROC\" data-name=\"/data/PROCEDURE/PROC_GRID/PROC\" data-required=\"true()  \" data-type-xml=\"select1\"><option value=\"\">...</option><option value=\"1\">Partial Mastectomy</option><option value=\"6\">Sentinel Lymph Node Dissection</option></select><span class=\"or-option-translations\" style=\"display:none;\">\n                </span><span class=\"or-required-msg active\" lang=\"\" data-i18n=\"constraint.required\">This field is required</span></label>\n            </section><div class=\"or-repeat-info\" data-name=\"/data/PROCEDURE/PROC_GRID\"></div>\n            </section><!--end of group -->\n            </section><!--end of group -->\n    <section class=\"or-group or-appearance-field-list\" name=\"/data/SPEC\"><h4><span lang=\"\" class=\"question-label active\">Specimens</span></h4><section class=\"or-group or-appearance-w6 or-appearance-no-collapse\" name=\"/data/SPEC/GPT\"><h4><span lang=\"\" class=\"question-label active\">Gross Pathology: Tumor</span></h4><label class=\"question or-appearance-w6 or-appearance-minimal\"><span lang=\"\" class=\"question-label active\"><h6>Tumor Type:</h6></span><span class=\"required\">*</span><select name=\"/data/SPEC/GPT/TUMTYP\" data-name=\"/data/SPEC/GPT/TUMTYP\" data-required=\"true()  \" data-type-xml=\"select1\"><option value=\"\">...</option><option value=\"1\">None Present</option></select><span class=\"or-option-translations\" style=\"display:none;\">\n                </span><span class=\"or-required-msg active\" lang=\"\" data-i18n=\"constraint.required\">This field is required</span></label>\n            </section><!--end of group -->\n            </section><!--end of group -->\n    <section class=\"or-group or-branch pre-init or-appearance-no-collapse\" name=\"/data/LYMPHNODES\" data-relevant=\"indexed-repeat( /data/PROCEDURE/PROC_GRID/PROC ,  /data/PROCEDURE/PROC_GRID , 1) = 6 or indexed-repeat( /data/PROCEDURE/PROC_GRID/PROC ,  /data/PROCEDURE/PROC_GRID , 2) = 6\"><h4><span lang=\"\" class=\"question-label active\">Lymph Nodes</span></h4><label class=\"question or-appearance-minimal\"><span lang=\"\" class=\"question-label active\">Lymph node dissection done?</span><select name=\"/data/LYMPHNODES/LYMNDISS\" data-name=\"/data/LYMPHNODES/LYMNDISS\" data-type-xml=\"select1\"><option value=\"\">...</option><option value=\"1\">Yes</option></select><span class=\"or-option-translations\" style=\"display:none;\">\n                </span></label>\n            </section><!--end of group -->\n  \n<fieldset id=\"or-calculated-items\" style=\"display:none;\"><label class=\"calculation non-select \"><input type=\"hidden\" name=\"/data/meta/instanceID\" data-calculate=\"concat('uuid:', uuid())\" data-type-xml=\"string\"></label></fieldset></form>",
    "xml_model": "<model><instance>\n        <data xmlns:enk=\"http://enketo.org/xforms\" xmlns:jr=\"http://openrosa.org/javarosa\" xmlns:oc=\"http://openclinica.org/xforms\" xmlns:orx=\"http://openrosa.org/xforms\" id=\"PSS\" version=\"1\">\n          <PROCEDURE>\n            <PROC_NOTE/>\n            <PROC_GRID jr:template=\"\">\n              <PROC/>\n            </PROC_GRID>\n          </PROCEDURE>\n          <SPEC>\n            <GPT>\n              <TUMTYP/>\n            </GPT>\n          </SPEC>\n          <LYMPHNODES>\n            <LYMNDISS/>\n          </LYMPHNODES>\n          <meta>\n            <instanceID/>\n          </meta>\n        </data>\n      </instance></model>"
