  "nested_repeats.xml": {
    "modifiedTime": 1748279922462,
    "html_form": "<form autocomplete=\"off\" novalidate=\"novalidate\" class=\"or clearfix\" dir=\"ltr\" data-form-id=\"nested_repeats\">\n<!--This form was created by transforming an ODK/OpenRosa-flavored (X)Form using an XSL stylesheet created by Enketo LLC.--><section class=\"form-logo\"></section><h3 dir=\"auto\" id=\"form-title\">Nested repeats Test</h3>\n  \n  \n    <section class=\"or-group \" name=\"/nested_repeats/kids\"><h4><span lang=\"\" class=\"question-label active\">Kids</span></h4><fieldset class=\"question simple-select \"><fieldset><legend><span lang=\"\" class=\"question-label active\">4. Do you have any kids?</span>\n                    </legend><div class=\"option-wrapper\"><label class=\"\"><input type=\"radio\" name=\"/nested_repeats/kids/has_kids\" data-name=\"/nested_repeats/kids/has_kids\" value=\"0\" data-type-xml=\"select1\"><span lang=\"\" class=\"option-label active\">no</span></label><label class=\"\"><input type=\"radio\" name=\"/nested_repeats/kids/has_kids\" data-name=\"/nested_repeats/kids/has_kids\" value=\"1\" data-type-xml=\"select1\"><span lang=\"\" class=\"option-label active\">yes</span></label></div></fieldset></fieldset><section class=\"or-group or-branch pre-init \" name=\"/nested_repeats/kids/kids_details\" data-relevant=\"/nested_repeats/kids/has_kids='1'\"><h4><span lang=\"\" class=\"question-label active\">4.1 Kids Details</span></h4><section class=\"or-repeat \" name=\"/nested_repeats/kids/kids_details\"><label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">4.1.1 Child's Name</span><input type=\"text\" name=\"/nested_repeats/kids/kids_details/kids_name\" data-type-xml=\"string\"></label><label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">4.1.2 Child's Age</span><input type=\"number\" name=\"/nested_repeats/kids/kids_details/kids_age\" data-type-xml=\"int\"></label><section class=\"or-group-data \" name=\"/nested_repeats/kids/kids_details/immunization_info\"><section class=\"or-repeat \" name=\"/nested_repeats/kids/kids_details/immunization_info\"><label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">An immunization record</span><input type=\"text\" name=\"/nested_repeats/kids/kids_details/immunization_info/vaccine\" data-type-xml=\"string\"></label><label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">date</span><input type=\"date\" name=\"/nested_repeats/kids/kids_details/immunization_info/date\" data-type-xml=\"date\"></label>\n            </section><div class=\"or-repeat-info\" data-name=\"/nested_repeats/kids/kids_details/immunization_info\"></div>\n            </section><!--end of group -->\n            </section><div class=\"or-repeat-info\" data-name=\"/nested_repeats/kids/kids_details\"></div>\n            </section><!--end of group --><section class=\"or-group \" name=\"/nested_repeats/kids/nested_group\"><h4><span lang=\"\" class=\"question-label active\">4.2 A Nested Group</span></h4><label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">4.3 A Nested Name</span><input type=\"text\" name=\"/nested_repeats/kids/nested_group/nested_name\" data-type-xml=\"string\"></label><label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">4.4 A Nested Age</span><input type=\"number\" name=\"/nested_repeats/kids/nested_group/nested_age\" data-type-xml=\"int\"></label>\n            </section><!--end of group -->\n            </section><!--end of group -->\n    <label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">5. Record your GPS coordinates.</span><span lang=\"\" class=\"or-hint active\">GPS coordinates can only be collected when outside.</span><input type=\"text\" name=\"/nested_repeats/gps\" data-type-xml=\"string\"></label>\n    <fieldset class=\"question simple-select \"><fieldset><legend><span lang=\"\" class=\"question-label active\">6. What web browsers do you use?</span><span lang=\"\" class=\"or-hint active\">Select all that apply.</span>\n                    </legend><div class=\"option-wrapper\"><label class=\"\"><input type=\"checkbox\" name=\"/nested_repeats/web_browsers\" value=\"firefox\" data-type-xml=\"select\"><span lang=\"\" class=\"option-label active\">Mozilla Firefox</span></label><label class=\"\"><input type=\"checkbox\" name=\"/nested_repeats/web_browsers\" value=\"chrome\" data-type-xml=\"select\"><span lang=\"\" class=\"option-label active\">Google Chrome</span></label><label class=\"\"><input type=\"checkbox\" name=\"/nested_repeats/web_browsers\" value=\"ie\" data-type-xml=\"select\"><span lang=\"\" class=\"option-label active\">Internet Explorer</span></label><label class=\"\"><input type=\"checkbox\" name=\"/nested_repeats/web_browsers\" value=\"safari\" data-type-xml=\"select\"><span lang=\"\" class=\"option-label active\">Safari</span></label></div></fieldset></fieldset>\n  \n<fieldset id=\"or-calculated-items\" style=\"display:none;\"><label class=\"calculation non-select \"><input type=\"hidden\" name=\"/nested_repeats/formhub/uuid\" data-calculate=\"'f19b44ccf710492eb4d1ed6f468324f1'\" data-type-xml=\"string\"></label></fieldset></form>",
    "xml_model": "<model><instance>\n        <nested_repeats xmlns:jr=\"http://openrosa.org/javarosa\" xmlns:orx=\"http://openrosa.org/xforms/\" id=\"nested_repeats\"><formhub><uuid/></formhub>\n          <kids>\n            <has_kids>1</has_kids>\n            <kids_details jr:template=\"\">\n              <kids_name/>\n              <kids_age/>\n              <immunization_info jr:template=\"\">\n                <vaccine/>\n                <date/>\n              </immunization_info>\n            </kids_details>\n            <kids_details>\n              <kids_name>Tom</kids_name>\n              <kids_age>2</kids_age>\n              <immunization_info>\n                <vaccine>Polio</vaccine>\n                <date/>\n              </immunization_info>\n              <immunization_info>\n                <vaccine>Rickets</vaccine>\n                <date/>\n              </immunization_info>\n            </kids_details>\n            <kids_details>\n              <kids_name>Dick</kids_name>\n              <kids_age>5</kids_age>\n              <immunization_info>\n                <vaccine>Malaria</vaccine>\n                <date/>\n              </immunization_info>\n              <immunization_info>\n                <vaccine>Flu</vaccine>\n                <date/>\n              </immunization_info>\n              <immunization_info>\n                <vaccine>Polio</vaccine>\n                <date/>\n              </immunization_info>\n            </kids_details>\n            <nested_group>\n              <nested_name/>\n              <nested_age/>\n            </nested_group>\n          </kids>\n          <gps/>\n          <web_browsers/>\n        <meta><instanceID/></meta></nested_repeats>\n      </instance></model>"
  },
