  "range.xml": {
    "modifiedTime": 1748279922463,
    "html_form": "<form autocomplete=\"off\" novalidate=\"novalidate\" class=\"or clearfix script-autocomplete theme-grid\" dir=\"ltr\" data-form-id=\"range\">\n<!--This form was created by transforming an ODK/OpenRosa-flavored (X)Form using an XSL stylesheet created by Enketo LLC.--><section class=\"form-logo\"></section><h3 dir=\"auto\" id=\"form-title\">A Demo Form</h3>\n  \n  \n    <label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">Range widget 1</span><span lang=\"\" class=\"or-hint active\">A horizontal range widget (type=range)</span><input type=\"number\" name=\"/range/range1\" data-type-xml=\"int\" min=\"0\" max=\"5\" step=\"1\"></label>\n    <label class=\"question non-select or-appearance-vertical\"><span lang=\"\" class=\"question-label active\">Range widget 2</span><span lang=\"\" class=\"or-hint active\">A vertical range widget (type=range, appearance=vertical)</span><input type=\"number\" name=\"/range/range2\" data-type-xml=\"decimal\" step=\"0.1\" min=\"0\" max=\"2\"></label>\n    <label class=\"question non-select or-appearance-no-ticks\"><span lang=\"\" class=\"question-label active\">Range widget 3</span><span lang=\"\" class=\"or-hint active\">A horizontal range widget without ticks (type=range, appearance=no-ticks)</span><input type=\"number\" name=\"/range/range3\" data-type-xml=\"int\" min=\"0\" max=\"5\" step=\"1\"></label>\n    <label class=\"question or-appearance-picker\"><span lang=\"\" class=\"question-label active\">Range picker widget 4</span><span lang=\"\" class=\"or-hint active\">A horizontal range widget without ticks (type=range, appearance=picker)</span><select name=\"/range/range4\" data-type-xml=\"int\" min=\"0\" max=\"5\" step=\"1\"><option value=\"\">...</option><option value=\"0\">0</option><option value=\"1\">1</option><option value=\"2\">2</option><option value=\"3\">3</option><option value=\"4\">4</option><option value=\"5\">5</option></select><span class=\"or-option-translations\" style=\"display:none;\">\n                </span></label>\n    <label class=\"question non-select or-appearance-rating\"><span lang=\"\" class=\"question-label active\">Rating widget 5</span><span lang=\"\" class=\"or-hint active\">A horizontal range widget without ticks (type=range, appearance=rating)</span><input type=\"number\" name=\"/range/range5\" data-type-xml=\"int\" min=\"0\" max=\"5\" step=\"1\"></label>\n    <label class=\"question non-select or-appearance-rating\"><span lang=\"\" class=\"question-label active\">Rating with default value</span><span lang=\"\" class=\"or-hint active\">A horizontal range widget without ticks (type=range, appearance=rating)</span><input type=\"number\" name=\"/range/range6\" data-type-xml=\"int\" readonly min=\"1\" max=\"10\" step=\"1\"></label>\n    <label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">Range with default value</span><span lang=\"\" class=\"or-hint active\">A horizontal range widget without ticks (type=range)</span><input type=\"number\" name=\"/range/range7\" data-type-xml=\"string\" min=\"1\" max=\"10\" step=\"1\"></label>\n    <label class=\"question non-select or-appearance-distress\"><span lang=\"\" class=\"question-label active\">Distress widget</span><span lang=\"\" class=\"or-hint active\">A highly specific widget to measure distress(type=range, appearance=distress)</span><input type=\"number\" name=\"/range/distress\" data-type-xml=\"int\" min=\"1\" max=\"10\" step=\"1\"></label>\n  \n<fieldset id=\"or-preload-items\" style=\"display:none;\"><label class=\"calculation non-select \"><input type=\"hidden\" name=\"/range/meta/instanceID\" data-preload=\"uid\" data-preload-params=\"\" data-type-xml=\"string\"></label></fieldset></form>",
    "xml_model": "<model><instance>\n        <range xmlns:jr=\"http://openrosa.org/javarosa\" xmlns:odk=\"http://www.opendatakit.org/xforms\" xmlns:orx=\"http://openrosa.org/xforms\" id=\"range\">\n          <range1/>\n          <range2/>\n          <range3/>\n          <range4/>\n          <range5/>\n          <range6>3</range6>\n          <range7>4</range7>\n          <distress/>\n          <meta>\n            <instanceID/>\n          </meta>\n        </range>\n      </instance></model>"
  },
