    "xml_model": "<model><instance>\n                <rank xmlns:jr=\"http://openrosa.org/javarosa\" xmlns:orx=\"http://openrosa.org/xforms\" xmlns:odk=\"http://www.opendatakit.org/xforms\" id=\"rank\">\n                    <s1/>\n                    <r1/>\n                    <r2/>\n                    <r3>foddertree beans cacao coffee foddergrass banana</r3>\n                    <r4/>\n                    <meta>\n                        <instanceID/>\n                    </meta>\n                </rank>\n            </instance><instance id=\"crop_list\">\n                <root xmlns:jr=\"http://openrosa.org/javarosa\" xmlns:orx=\"http://openrosa.org/xforms\" xmlns:odk=\"http://www.opendatakit.org/xforms\">\n                    <item>\n                        <label>Banana</label>\n                        <name>banana</name>\n                    </item>\n                    <item>\n                        <label>Beans</label>\n                        <name>beans</name>\n                    </item>\n                    <item>\n                        <label>Cacao</label>\n                        <name>cacao</name>\n                    </item>\n                    <item>\n                        <label>Coffee</label>\n                        <name>coffee</name>\n                    </item>\n                    <item>\n                        <label>Fodder Grass</label>\n                        <name>foddergrass</name>\n                    </item>\n                    <item>\n                        <label>Fodder Tree</label>\n                        <name>foddertree</name>\n                    </item>\n                </root>\n            </instance></model>"
