    "html_form": "<form autocomplete=\"off\" novalidate=\"novalidate\" class=\"or clearfix\" dir=\"ltr\" data-form-id=\"repeat-count-calc-only\">\n<!--This form was created by transforming an ODK/OpenRosa-flavored (X)Form using an XSL stylesheet created by Enketo LLC.--><section class=\"form-logo\"></section><h3 dir=\"auto\" id=\"form-title\">repeat-count-calc-only</h3>\n    \n    \n        <fieldset class=\"question or-appearance-likert\"><fieldset><legend><span lang=\"\" class=\"question-label active\">Enketo is incredible.</span>\n                    </legend><div class=\"option-wrapper\"><label class=\"\"><input type=\"radio\" name=\"/repeat-count-calc-only/a\" data-name=\"/repeat-count-calc-only/a\" value=\"1\" data-type-xml=\"select1\"><span lang=\"\" class=\"option-label active\">strongly disagree</span></label><label class=\"\"><input type=\"radio\" name=\"/repeat-count-calc-only/a\" data-name=\"/repeat-count-calc-only/a\" value=\"2\" data-type-xml=\"select1\"><span lang=\"\" class=\"option-label active\">disagree</span></label><label class=\"\"><input type=\"radio\" name=\"/repeat-count-calc-only/a\" data-name=\"/repeat-count-calc-only/a\" value=\"3\" data-type-xml=\"select1\"><span lang=\"\" class=\"option-label active\">neither agree nor disagree</span></label><label class=\"\"><input type=\"radio\" name=\"/repeat-count-calc-only/a\" data-name=\"/repeat-count-calc-only/a\" value=\"4\" data-type-xml=\"select1\"><span lang=\"\" class=\"option-label active\">agree</span></label><label class=\"\"><input type=\"radio\" name=\"/repeat-count-calc-only/a\" data-name=\"/repeat-count-calc-only/a\" value=\"5\" data-type-xml=\"select1\"><span lang=\"\" class=\"option-label active\">strongly agree</span></label></div></fieldset></fieldset>\n        <section class=\"or-group-data \" name=\"/repeat-count-calc-only/rep\"><section class=\"or-repeat \" name=\"/repeat-count-calc-only/rep\">\n            </section><div class=\"or-repeat-info\" data-name=\"/repeat-count-calc-only/rep\" data-repeat-count=\" /repeat-count-calc-only/rep_count \"></div>\n            </section><!--end of group -->\n    \n<fieldset id=\"or-calculated-items\" style=\"display:none;\"><label class=\"calculation non-select \"><input type=\"hidden\" name=\"/repeat-count-calc-only/rep_count\" data-calculate=\"2\" data-type-xml=\"string\"></label><label class=\"calculation non-select \"><input type=\"hidden\" name=\"/repeat-count-calc-only/rep/calc1\" data-calculate=\"position(..)+1\" data-type-xml=\"string\"></label><label class=\"calculation non-select \"><input type=\"hidden\" name=\"/repeat-count-calc-only/rep/calc2\" data-calculate=\"position(..)+2\" data-type-xml=\"string\"></label><label class=\"calculation non-select \"><input type=\"hidden\" name=\"/repeat-count-calc-only/meta/instanceID\" data-calculate=\"concat('uuid:', uuid())\" data-type-xml=\"string\"></label></fieldset></form>",
