  "repeat-count-relevant-on-calculate.xml": {
    "modifiedTime": 1748279922464,
    "html_form": "<form autocomplete=\"off\" novalidate=\"novalidate\" class=\"or clearfix\" dir=\"ltr\" data-form-id=\"relevance_on_calc_repeat_count\">\n<!--This form was created by transforming an ODK/OpenRosa-flavored (X)Form using an XSL stylesheet created by Enketo LLC.--><section class=\"form-logo\"></section><h3 dir=\"auto\" id=\"form-title\">Repeat count 0 with relevant on calculate</h3>\n\t\n\t\n\t\t<label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">Count</span><input type=\"number\" name=\"/data/count\" data-type-xml=\"int\"></label>\n\t\t<section class=\"or-group \" name=\"/data/repeat\"><h4><span lang=\"\" class=\"question-label active\">Repeat</span></h4><section class=\"or-repeat \" name=\"/data/repeat\"><label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">Q1</span><input type=\"number\" name=\"/data/repeat/q1\" data-type-xml=\"int\"></label>\n            </section><div class=\"or-repeat-info\" data-name=\"/data/repeat\" data-repeat-count=\" /data/count \"></div>\n            </section><!--end of group -->\n\t\n<fieldset id=\"or-preload-items\" style=\"display:none;\"><label class=\"calculation non-select \"><input type=\"hidden\" name=\"/data/meta/instanceID\" data-preload=\"uid\" data-preload-params=\"\" data-type-xml=\"string\"></label></fieldset><fieldset id=\"or-calculated-items\" style=\"display:none;\"><label class=\"or-branch pre-init calculation non-select \"><input type=\"hidden\" name=\"/data/repeat/q1_x2\" data-relevant=\" ../q1  &gt; 0\" data-calculate=\" ../q1  * 2\" data-type-xml=\"string\"></label></fieldset></form>",
    "xml_model": "<model xmlns:odk=\"http://www.opendatakit.org/xforms\" odk:xforms-version=\"1.0.0\"><instance>\n\t\t\t\t<data xmlns:jr=\"http://openrosa.org/javarosa\" id=\"relevance_on_calc_repeat_count\">\n\t\t\t\t\t<count>1</count>\n\t\t\t\t\t<repeat>\n\t\t\t\t\t\t<q1/>\n\t\t\t\t\t\t<q1_x2/>\n\t\t\t\t\t</repeat>\n\t\t\t\t\t<meta>\n\t\t\t\t\t\t<instanceID/>\n\t\t\t\t\t</meta>\n\t\t\t\t</data>\n\t\t\t</instance></model>"
  },
