    "xml_model": "<model><instance>\n        <data xmlns:jr=\"http://openrosa.org/javarosa\" xmlns:orx=\"http://openrosa.org/xforms\" id=\"repeat-count-relevant\">\n          <q1/>\n          <rep jr:template=\"\">\n            <q2/>\n          </rep>\n          <meta>\n            <instanceID/>\n          </meta>\n        </data>\n      </instance></model>"
