    "html_form": "<form autocomplete=\"off\" novalidate=\"novalidate\" class=\"or clearfix\" dir=\"ltr\" data-form-id=\"repeat-count-widget-global-init\">\n<!--This form was created by transforming an ODK/OpenRosa-flavored (X)Form using an XSL stylesheet created by Enketo LLC.--><section class=\"form-logo\"></section><h3 dir=\"auto\" id=\"form-title\">Global init of widgets in repeat count (default=0)</h3>\n    \n    \n        <label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">Repeat count</span><input type=\"number\" name=\"/data/rep-count\" data-type-xml=\"int\"></label>\n        <section class=\"or-group \" name=\"/data/rep\"><h4><span lang=\"\" class=\"question-label active\">Rep</span></h4><section class=\"or-repeat \" name=\"/data/rep\"><label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">Decimal input</span><input type=\"number\" name=\"/data/rep/dec\" data-type-xml=\"decimal\" step=\"any\"></label>\n            </section><div class=\"or-repeat-info\" data-name=\"/data/rep\" data-repeat-count=\"/data/rep-count\"></div>\n            </section><!--end of group -->\n    \n<fieldset id=\"or-preload-items\" style=\"display:none;\"><label class=\"calculation non-select \"><input type=\"hidden\" name=\"/data/meta/instanceID\" data-preload=\"uid\" data-preload-params=\"\" data-type-xml=\"string\"></label></fieldset></form>",
    "xml_model": "<model xmlns:odk=\"http://www.opendatakit.org/xforms\" odk:xforms-version=\"1.0.0\"><instance>\n                <data xmlns:jr=\"http://openrosa.org/javarosa\" xmlns:orx=\"http://openrosa.org/xforms\" id=\"repeat-count-widget-global-init\">\n                    <rep-count/>\n                    <rep jr:template=\"\">\n                        <grp_plot>\n                            <plot_id/>\n                            <plot_size/>\n                            <plot_crops/>\n                        </grp_plot>\n                    </rep>\n                    <rep>\n                        <grp_plot>\n                            <plot_id/>\n                            <plot_size/>\n                            <plot_crops/>\n                        </grp_plot>\n                    </rep>\n                    <meta>\n                        <instanceID/>\n                    </meta>\n                </data>\n            </instance></model>"
