  "repeat-count.xml": {
    "modifiedTime": 1748279922464,
    "html_form": "<form autocomplete=\"off\" novalidate=\"novalidate\" class=\"or clearfix\" dir=\"ltr\" data-form-id=\"dynamic-repeat-count\">\n<!--This form was created by transforming an ODK/OpenRosa-flavored (X)Form using an XSL stylesheet created by Enketo LLC.--><section class=\"form-logo\"></section><h3 dir=\"auto\" id=\"form-title\">dynamic-repeat-count</h3>\n  \n  \n    <label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">How many repeats?</span><input type=\"number\" name=\"/dynamic-repeat-count/count\" data-type-xml=\"int\"></label>\n    <section class=\"or-group \" name=\"/dynamic-repeat-count/rep\"><h4><span lang=\"\" class=\"question-label active\">Repeat with count</span></h4><section class=\"or-repeat \" name=\"/dynamic-repeat-count/rep\"><label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">Enter text</span><input type=\"text\" name=\"/dynamic-repeat-count/rep/txt\" data-type-xml=\"string\"></label><label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">Enter number</span><input type=\"number\" name=\"/dynamic-repeat-count/rep/num\" data-type-xml=\"int\"></label>\n            </section><div class=\"or-repeat-info\" data-name=\"/dynamic-repeat-count/rep\" data-repeat-count=\" /dynamic-repeat-count/rep_count \"></div>\n            </section><!--end of group -->\n    <label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">Number of repeats present</span><input type=\"text\" name=\"/dynamic-repeat-count/sum_note\" data-calculate=\"count( /dynamic-repeat-count/rep )\" data-type-xml=\"string\" readonly></label>\n    <label class=\"question non-select \"><span lang=\"\" class=\"question-label active\">Number text inputs present</span><input type=\"text\" name=\"/dynamic-repeat-count/txtsum_note\" data-calculate=\"count( /dynamic-repeat-count/rep/txt )\" data-type-xml=\"string\" readonly></label>\n  \n<fieldset id=\"or-calculated-items\" style=\"display:none;\"><label class=\"or-branch pre-init calculation non-select \"><input type=\"hidden\" name=\"/dynamic-repeat-count/rep_count\" data-relevant=\"true()\" data-calculate=\" /dynamic-repeat-count/count \" data-type-xml=\"string\"></label><label class=\"calculation non-select \"><input type=\"hidden\" name=\"/dynamic-repeat-count/meta/instanceID\" data-calculate=\"concat('uuid:', uuid())\" data-type-xml=\"string\"></label></fieldset></form>",
    "xml_model": "<model><instance>\n        <dynamic-repeat-count xmlns:jr=\"http://openrosa.org/javarosa\" xmlns:oc=\"http://openclinica.org/xforms\" xmlns:orx=\"http://openrosa.org/xforms\" id=\"dynamic-repeat-count\">\n          <count>2</count>\n          <rep_count/>\n          <rep jr:template=\"\">\n            <txt/>\n            <num>5</num>\n          </rep>\n          <sum_note/>\n          <txtsum_note/>\n          <meta>\n            <instanceID/>\n          </meta>\n        </dynamic-repeat-count>\n      </instance></model>"
  },
