  "repeat-multiple-shared-datalist-itemsets.xml": {
    "modifiedTime": 1748279922465,
    "html_form": "<form autocomplete=\"off\" novalidate=\"novalidate\" class=\"or clearfix\" dir=\"ltr\" data-form-id=\"repeat-multiple-shared-datalist-itemsets\">\n<!--This form was created by transforming an ODK/OpenRosa-flavored (X)Form using an XSL stylesheet created by Enketo LLC.--><section class=\"form-logo\"></section><h3 dir=\"auto\" id=\"form-title\">repeat-multiple-shared-datalist-itemsets</h3><select id=\"form-languages\" style=\"display:none;\" data-default-lang=\"\"><option value=\"en\" data-dir=\"ltr\">English</option> </select>\n    \n    \n        <section class=\"or-group \" name=\"/data/rep\"><h4><span lang=\"\" class=\"question-label active\">Repeat with multiple shared itemsets which render shared `datalist` elements</span></h4><section class=\"or-repeat \" name=\"/data/rep\"><label class=\"question or-appearance-autocomplete\"><input name=\"/data/rep/item-0\" data-type-xml=\"string\" type=\"text\" list=\"datarepitem0\"><datalist id=\"datarepitem0\"><option class=\"itemset-template\" value=\"\" data-items-path=\"instance('items-0')/item\">...</option></datalist><span class=\"or-option-translations\" style=\"display:none;\">\n                </span><span class=\"itemset-labels\" data-value-ref=\"name\" data-label-type=\"itext\" data-label-ref=\"itextId\"><span lang=\"en\" class=\"option-label active\" data-itext-id=\"items-0-0\">items-0-0</span> </span></label><label class=\"question or-appearance-search\"><input name=\"/data/rep/item-1\" data-type-xml=\"string\" type=\"text\" list=\"datarepitem1\"><datalist id=\"datarepitem1\"><option class=\"itemset-template\" value=\"\" data-items-path=\"instance('items-1')/item\">...</option></datalist><span class=\"or-option-translations\" style=\"display:none;\">\n                </span><span class=\"itemset-labels\" data-value-ref=\"name\" data-label-type=\"itext\" data-label-ref=\"itextId\"><span lang=\"en\" class=\"option-label active\" data-itext-id=\"items-1-0\">items-1-0</span> </span></label>\n            </section><div class=\"or-repeat-info\" data-name=\"/data/rep\"></div>\n            </section><!--end of group -->\n    \n</form>",
    "xml_model": "<model xmlns:odk=\"http://www.opendatakit.org/xforms\" odk:xforms-version=\"1.0.0\"><instance>\n                <data xmlns:jr=\"http://openrosa.org/javarosa\" xmlns:orx=\"http://openrosa.org/xforms\" id=\"repeat-multiple-shared-datalist-itemsets\">\n                    <rep>\n                        <item-0/>\n                        <item-1/>\n                    </rep>\n                <meta><instanceID/></meta></data>\n            </instance><instance id=\"items-0\">\n                <item xmlns:jr=\"http://openrosa.org/javarosa\" xmlns:orx=\"http://openrosa.org/xforms\">\n                    <itextId>items-0-0</itextId>\n                    <name>items 0 0</name>\n                </item>\n            </instance><instance id=\"items-1\">\n                <item xmlns:jr=\"http://openrosa.org/javarosa\" xmlns:orx=\"http://openrosa.org/xforms\">\n                    <itextId>items-1-0</itextId>\n                    <name>items 1 0</name>\n                </item>\n            </instance></model>"
  },
